# Claude Zombies - Nacht der Untoten
#
# Modeled on the original Call of Duty: World at War map. Tight spawn
# bunker in the SW corner with all four boarded windows clustered around
# you, two debris-doors leading out (north "Help" stairs, east "Alley"),
# and a final gated back room holding the Pack-a-Punch.

NAME Nacht der Untoten

# --- Spawns (inside the SW bunker) ---
SPAWN  -32 -32
SPAWN  -30 -32
SPAWN  -32 -30
SPAWN  -34 -30

# --- SW SPAWN BUNKER (x: -40..-25, z: -40..-25) ---
# North wall (along z=-25) with a $1000 stairs door at x=-32
WALL  -37.5 2.5 -25     5 5 1
WALL  -27.0 2.5 -25     4 5 1
DOOR  -32.0 2.5 -25     6 5 1   1000

# East wall (along x=-25) with a $1000 alley door at z=-32
WALL  -25.0 2.5 -37.5   1 5 5
WALL  -25.0 2.5 -27.0   1 5 4
DOOR  -25.0 2.5 -32.0   1 5 6   1000

# Spawn-bunker cover (debris piled in the corners)
OBSTACLE -33 1.0 -28    3 2 3
OBSTACLE -28 0.5 -33    4 1 3
OBSTACLE -38 1.5 -33    3 3 3

# --- HELP / MAIN HALL (everything between the bunker and the back room) ---
OBSTACLE -10 1.0 -18    3 2 3
OBSTACLE  10 1.0 -18    3 2 3
OBSTACLE   0 1.0  -8    4 2 2
OBSTACLE -22 1.0  -5    3 2 3
OBSTACLE  22 1.0  -5    3 2 3
OBSTACLE   0 1.0  10    6 2 3

# --- BACK ROOM (NE corner, x: 15..40, z: 15..40) holding the PaP ---
# South wall (along z=15) closed full width
WALL   27.5 2.5  15    23 5 1
# West wall (along x=15) with the $1500 entry door at z=25
WALL   15.0 2.5  18.5   1 5 7
WALL   15.0 2.5  34.0   1 5 12
DOOR   15.0 2.5  25.0   1 5 6   1500

OBSTACLE  25 1.0 25     3 2 3
OBSTACLE  32 1.0 22     3 2 3
OBSTACLE  22 0.5 35     6 1 3

# --- Windows: all four crammed around the spawn bunker ---
WINDOW -35.0 -40.0    0  1   -1
WINDOW -28.0 -40.0    0  1   -1
WINDOW -40.0 -35.0    1  0   -1
WINDOW -40.0 -28.0    1  0   -1

# --- Wall buys ---
# M1A1-style rifle right next to spawn on the south arena wall
WALLBUY -32.0 -39.45   0  1   RIFLE
# SMG further along, in the hall outside the bunker
WALLBUY -39.45 -10.0   1  0   SMG
# Shotgun on the east arena wall mid-map
WALLBUY  39.45 -10.0  -1  0   SHOTGUN
# Second rifle on the north arena wall, just outside the back-room door
WALLBUY -10.0  39.45   0 -1   RIFLE
# Ray gun gated in the back room
WALLBUY  30.0  39.45   0 -1   RAYGUN

# --- Perks (one in spawn, rest spread through the hall + back room) ---
PERK -32.0 -28.0   SPEED
PERK -15.0  -8.0   JUG
PERK   8.0   0.0   DTAP
PERK  30.0  30.0   STAMIN

# --- Mystery box: out in the main hall, classic Nacht "first random box" spot ---
MBOX  0  12

# --- Pack-a-Punch: tucked into the far NE corner of the back room ---
PAP  35  35
